// Script Continued Below
/*jshint esnext: true */
(function executeRule(current, previous /*null when async*/) {
	//Stamp version number onto record during initialization
	tcs = new TaskerCommonScriptingMethods();
	var result = tcs.queryRelated("sys_scope", [{"name":"Tasker"}], function(record){ return record.version; });
	if(result && result.length > 0)
		current.tasker_app_version = result[0];
	if(current.parent){
		// STRY0076596 - when Task has u_wait_for_subtasks_to_finish checked set task owner to parent task owner or originator
		if(current.u_wait_for_subtasks_to_finish){
			current.u_task_requester = current.parent.u_task_requester;
		}else{
			// STRY0078378 - if set by the user on creation, then don't override it 
			if(!current.u_task_requester){
				if(current.parent.assigned_to && current.parent.state != tcs.UNASSIGNED_STATE){
					current.u_task_requester = current.parent.assigned_to;
				} else {
					// STRY0078378 - if task owner of parent not set, set the owner of the subtask to the originator of the parent
					if (current.parent.u_task_requester){
						current.u_task_requester = current.parent.u_task_requester;
					} else {
						current.u_task_requester = current.parent.originator;
					}
				}
			}
		}
	} else {
		// STRY0078378 - if set by the user on creation, then don't override it 
		if(!current.u_task_requester){
			current.u_task_requester = current.originator;
		}
	}
})(current, previous);
